defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller

  alias MyApp.Accounts
  alias MyApp.Accounts.User

  action_fallback MyAppWeb.FallbackController

  # Update action with proper authorization and field allowlisting
  def update(conn, %{"id" => id} = params) do
    current_user = conn.assigns[:current_user]

    with :ok <- authorize_update(current_user, id),
         {:ok, user} <- Accounts.get_user(id),
         :ok <- verify_same_tenant(current_user, user),
         sanitized_params <- sanitize_params(params, current_user),
         {:ok, updated_user} <- Accounts.update_user(user, sanitized_params) do
      conn
      |> put_status(:ok)
      |> render("show.json", user: updated_user)
    else
      {:error, :not_found} ->
        conn |> put_status(:not_found) |> json(%{error: "User not found"})

      {:error, :unauthorized} ->
        conn |> put_status(:forbidden) |> json(%{error: "Not authorized"})

      {:error, %Ecto.Changeset{} = changeset} ->
        conn |> put_status(:unprocessable_entity) |> render("error.json", changeset: changeset)
    end
  end

  # Only admins can update other users; regular users can only update themselves
  defp authorize_update(%User{id: user_id, role: role}, target_id) do
    cond do
      to_string(user_id) == to_string(target_id) -> :ok
      role in [:admin, "admin"] -> :ok
      true -> {:error, :unauthorized}
    end
  end

  defp authorize_update(nil, _target_id), do: {:error, :unauthorized}

  # Enforce tenant scoping: users can only interact within their own tenant
  defp verify_same_tenant(%User{tenant_id: tenant_id}, %User{tenant_id: tenant_id}), do: :ok
  defp verify_same_tenant(_, _), do: {:error, :unauthorized}

  # Allowlist of fields based on role — never allow mass assignment of privileged fields
  defp sanitize_params(params, %User{role: role}) do
    base_allowed = ["name", "email", "phone", "avatar_url"]

    admin_allowed = ["is_active", "department"]

    allowed_fields =
      if role in [:admin, "admin"] do
        base_allowed ++ admin_allowed
      else
        base_allowed
      end

    # Strip "role", "tenant_id", "is_superadmin", "id", and any other privileged fields
    Map.take(params, allowed_fields)
  end
