defmodule MyApp.Accounts.User do
  use Ecto.Schema
  import Ecto.Changeset

  schema "users" do
    field :name, :string
    field :email, :string
    field :phone, :string
    field :avatar_url, :string
    field :role, :string, default: "user"
    field :tenant_id, :integer
    field :is_active, :boolean, default: true
    field :is_superadmin, :boolean, default: false
    field :department, :string
    field :password_hash, :string

    timestamps()
  end

  # Public-facing changeset with strict field allowlist — never cast privileged fields here
  @allowed_fields ~w(name email phone avatar_url)a
  @admin_additional_fields ~w(is_active department)a

  def changeset(user, attrs) do
    user
    |> cast(attrs, @allowed_fields)
    |> validate_required([:name, :email])
    |> validate_format(:email, ~r/^[^\s]+@[^\s]+\.[^\s]+$/)
    |> validate_length(:name, min: 1, max: 255)
    |> unique_constraint(:email)
  end

  def admin_changeset(user, attrs) do
    user
    |> cast(attrs, @allowed_fields ++ @admin_additional_fields)
    |> validate_required([:name, :email])
    |> validate_format(:email, ~r/^[^\s]+@[^\s]+\.[^\s]+$/)
    |> validate_length(:name, min: 1, max: 255)
    |> unique_constraint(:email)
  end

  # Role changes require a dedicated, separately authorized function
  def role_changeset(user, attrs) do
    user
    |> cast(attrs, [:role])
    |> validate_inclusion(:role, ["user", "admin", "moderator"])
  end
end

defmodule MyApp.Accounts do
  alias MyApp.Repo
  alias MyApp.Accounts.User

  import Ecto.Query

  def get_user(id) do
    case Repo.get(User, id) do
      nil -> {:error, :not_found}
      user -> {:ok, user}
    end
  end

  # Scoped query: always scope to tenant for list operations
  def list_users_for_tenant(tenant_id) do
    User
    |> where([u], u.tenant_id == ^tenant_id)
    |> Repo.all()
  end

  def update_user(%User{} = user, attrs) do
    user
    |> User.changeset(attrs)
    |> Repo.update()
  end

  def admin_update_user(%User{} = user, attrs) do
    user
    |> User.admin_changeset(attrs)
    |> Repo.update()
  end
end